import{C as t,o as n,c as l,a5 as i,E as o}from"./chunks/framework.CW28V7p_.js";const h=JSON.parse('{"title":"5. Jito Block Engine deep dive","description":"","frontmatter":{},"headers":[],"relativePath":"module-7/5-jito-block-engine.md","filePath":"module-7/5-jito-block-engine.md","lastUpdated":1780937944000}'),r={name:"module-7/5-jito-block-engine.md"},u=Object.assign(r,{setup(p){const e={id:"m7-5-jito-be",title:"🧠 Mini-check: Jito BE deep",intro:"2 питання.",questions:[{type:"mcq",q:"Jito Block Engine geographic considerations?",options:["Regional engines (Frankfurt, Tokyo, NY, Singapore, Salt Lake) reduce latency для local searchers","Validator connects до closest regional BE для best bundle quality","Single global BE handles все mainnet","BE choice impacts MEV income — closer searchers = більше bundles"],correct:[0,1,3],explanation:"Regional BEs critical. Single global wouldn't scale. Module 7.5."},{type:"explain",q:"Поясни Jito tip mechanism і чому it differs з priority fee.",ideal:`Priority fee (Module 3.3): pay-per-CU bid for leader inclusion. Standard Solana mechanism — works для будь-якого validator. Used для landing TX у congested moments.

Jito tip: payment у bundle для Jito-Solana validator (specifically). Not a per-CU bid — direct lamport amount in special "tip account" included у bundle.

Differences:
1. Recipient: priority fee → 50% leader/50% burn. Jito tip → 100% specific validator (50% operator, 50% stakers через split).
2. Validator selection: priority fee works для будь-який validator. Jito tip тільки для Jito-Solana validators.
3. Inclusion guarantee: high priority fee = better but not guaranteed inclusion. Jito tip + bundle через block engine = directly tells validator "include this bundle".
4. Use case: priority fee — для standard TX urgency. Jito tip — для MEV bundle execution (atomic multi-TX operations).

For LumLabs running Jito-Solana mainnet: both income streams. Priority fees from regular TX traffic. Jito tips from MEV bundles. Combined ~10-30% боку інкомe.`,explanation:"Module 7.5."}]};return(d,a)=>{const s=t("Quiz");return n(),l("div",null,[a[0]||(a[0]=i("",47)),o(s,{data:e}),a[1]||(a[1]=i("",6))])}}});export{h as __pageData,u as default};
